function arrayToSourceLines (array, indentCount = 0) {
  return createLines(indentCount, lines => {
    const contentLines = createLines(1, lines => {
      for (const value of array) {
        addLinesFromValue(lines, value, '', ',')
      }
    })
    if (contentLines.length === 0) {
      lines.push('[]')
    } else if (contentLines.length <= MAX_SINGLE_LINE_ARRAY_LENGTH) {
      const [first] = contentLines
      first.line = contentLines.map(({ line }) => line.substring(0, line.length - 1)).join(', ')
      first.line = `[${first.line}]`
      first.spaces--
      lines.push(first)
    } else {
      lines.push('[', ...contentLines, ']')
    }
  })
}

(code, language) => {
  const attrs = {
    class: `hljs ${language} p-2`,
    translate: 'no'
  }

  const [, filename] = RX_CODE_FILENAME.exec(code) || []
  if (filename) {
    attrs['data-filename'] = filename
    code = code.replace(RX_CODE_FILENAME, '')
  }

  const validLang = !!(language && hljs.getLanguage(language))
  const highlighted = validLang ? hljs.highlight(code, { language }).value : code

  const attrsMarkup = Object.keys(attrs).reduce(
    (markup, attr) => `${markup}${markup ? ' ' : ''}${attr}="${attrs[attr]}"`,
    ''
  )

  return `<div class="bd-code"><pre ${attrsMarkup}>${highlighted}</pre></div>`
}

onKeydown(event) {
  const { keyCode } = event
  if (
    this.isInteractive &&
    arrayIncludes([CODE_LEFT, CODE_DOWN, CODE_RIGHT, CODE_UP], keyCode)
  ) {
    stopEvent(event, { propagation: false })
    const value = toInteger(this.localValue, 0)
    const min = this.showClear ? 0 : 1
    const stars = this.computedStars
    // In RTL mode, LEFT/RIGHT are swapped
    const amountRtl = this.isRTL ? -1 : 1
    if (keyCode === CODE_LEFT) {
      this.localValue = clampValue(value - amountRtl, min, stars) || null
    } else if (keyCode === CODE_RIGHT) {
      this.localValue = clampValue(value + amountRtl, min, stars)
    } else if (keyCode === CODE_DOWN) {
      this.localValue = clampValue(value - 1, min, stars) || null
    } else if (keyCode === CODE_UP) {
      this.localValue = clampValue(value + 1, min, stars)
    }
  }
}

computedProps() {
  const { event, prefetch, routerTag } = this
  return this.isRouterLink
    ? {
        ...pluckProps(
          omit(
            { ...routerLinkProps, ...(this.computedTag === 'nuxt-link' ? nuxtLinkProps : {}) },
            ['event', 'prefetch', 'routerTag']
          ),
          this
        ),
        // Only add these props, when actually defined
        ...(event ? { event } : {}),
        ...(isBoolean(prefetch) ? { prefetch } : {}),
        // Pass `router-tag` as `tag` prop
        ...(routerTag ? { tag: routerTag } : {})
      }
    : {}
}

getPageInfo(pageNumber) {
  if (
    !isArray(this.pages) ||
    this.pages.length === 0 ||
    isUndefined(this.pages[pageNumber - 1])
  ) {
    const link = `${this.baseUrl}${pageNumber}`
    return {
      link: this.useRouter ? { path: link } : link,
      text: toString(pageNumber)
    }
  }
  const info = this.pages[pageNumber - 1]
  if (isObject(info)) {
    const link = info.link
    return {
      // Normalize link for router use
      link: isObject(link) ? link : this.useRouter ? { path: link } : link,
      // Make sure text has a value
      text: toString(info.text || pageNumber)
    }
  } else {
    return { link: toString(info), text: toString(pageNumber) }
  }
}

