formatNative(value: Date | null | undefined) {
    const date = new Date(value!)
    if (value && !isNaN(date.valueOf())) {
        const year = date.getFullYear()
        const month = date.getMonth() + 1
        const day = date.getDate()
        const hours = date.getHours()
        const minutes = date.getMinutes()
        const seconds = date.getSeconds()
        return year + '-' +
            ((month < 10 ? '0' : '') + month) + '-' +
            ((day < 10 ? '0' : '') + day) + 'T' +
            ((hours < 10 ? '0' : '') + hours) + ':' +
            ((minutes < 10 ? '0' : '') + minutes) + ':' +
            ((seconds < 10 ? '0' : '') + seconds)
    }
    return ''
}

computedSrcset() {
    if (this.srcset) {
        if (!this.webpSupported && this.isWepb && this.webpFallback && this.webpFallback.startsWith('.')) {
            return this.srcset.replace(/\.webp/gi, `${this.webpFallback}`)
        }
        return this.srcset
    }
    if (
        this.srcsetSizes && Array.isArray(this.srcsetSizes) && this.srcsetSizes.length > 0
    ) {
        return this.srcsetSizes.map((size) => {
            return `${this.srcsetFormatter(this.computedSrc!, size, this)} ${size}w`
        }).join(',')
    }
    return undefined
}

reset(parent: MenuItemContainer | null, menu: MenuInstance | null) {
    if (parent == null) {
        return
    }
    parent.menuItems.forEach((item) => {
        if (item !== this) {
            this.reset(item, menu)
            if (
                !parent.$data._isMenu ||
                (parent.$data._isMenu && (parent as MenuInstance).accordion)
            ) {
                item.newExpanded = false
                item.$emit('update:expanded', item.newExpanded)
            }
            if (menu && menu.activable) {
                item.newActive = false
                item.$emit('update:modelValue', item.newActive)
            }
        }
    })
}

set(value: number | string | null | undefined) {
    // Parses the number, so that "0" => 0, and "invalid" => null
    let newValue = (Number(value) === 0) ? 0 : (Number(value) || null)
    if (value === '' || value === undefined || value === null) {
        newValue = null
    }
    this.newValue = newValue
    if (newValue === null) {
        this.$emit('update:modelValue', newValue)
    // I decided to comment out `newValue !== '-0'` until we fix
    // the regression of https://github.com/buefy/buefy/pull/3170
    } else if (!isNaN(newValue)/* && newValue !== '-0' */) {
        this.$emit('update:modelValue', Number(newValue))
    }
    this.$nextTick(() => {
        if (this.$refs.input) {
            (this.$refs.input as BInputInstance).checkHtml5Validity()
        }
    })
}

sortMultiColumn(column: ITableColumn | TableColumnOrder) {
    this.currentSortColumn = BLANK_COLUMN
    if (!this.backendSorting) {
        const existingPriority = this.sortMultipleDataLocal.filter((i) =>
            i.field === column.field)[0]
        if (existingPriority) {
            existingPriority.order = existingPriority.order === 'desc' ? 'asc' : 'desc'
        } else {
            this.sortMultipleDataLocal.push({
                field: column.field,
                order: this.isAsc ? 'asc' : 'desc',
                customSort: column.customSort
            })
        }
        this.doSortMultiColumn()
    }
}

giveFocusToTab(tab: HTMLElement | ComponentPublicInstance | ComponentPublicInstance[]) {
    if (Array.isArray(tab)) {
        // Vue ≥ v3.0 < v3.2.25, refs in v-for are stored as a single object,
        // but ≥ v3.2.25, refs in v-for are stored in an array (same as Vue 2)
        tab = tab[0]
        if (tab == null) {
            return
        }
    }
    if (
        (tab as ComponentPublicInstance).$el &&
        (tab as ComponentPublicInstance).$el.focus
    ) {
        (tab as ComponentPublicInstance).$el.focus()
    } else if ((tab as HTMLElement).focus) {
        (tab as HTMLElement).focus()
    }
}

getHue() {
    const [red, green, blue] = Array.from(this.$channels).map((c) => c / 255)
    const [min, max] = [Math.min(red, green, blue), Math.max(red, green, blue)]
    const delta = max - min
    let hue = 0

    if (delta === 0) {
        return hue
    }

    if (red === max) {
        hue = ((green - blue) / delta) % 6
    } else if (green === max) {
        hue = (blue - red) / delta + 2
    } else {
        hue = (red - green) / delta + 4
    }

    hue *= 60
    while (hue !== -Infinity && hue < 0) hue += 360

    return Math.round(hue % 360)
}

updateDateSelected(
    hours: number | null,
    minutes: number | null,
    seconds: number | null,
    meridiens: string | null
) {
    if (hours != null && minutes != null &&
        ((!this.isHourFormat24 && meridiens !== null) || this.isHourFormat24)) {
        let time = null
        if (this.computedValue && !isNaN(this.computedValue.valueOf())) {
            time = new Date(this.computedValue)
        } else {
            time = this.timeCreator()
            time.setMilliseconds(0)
        }
        time.setHours(hours)
        time.setMinutes(minutes)
        time.setSeconds(seconds!)

        if (!isNaN(time.getTime())) this.computedValue = new Date(time.getTime())
    }
}

buildStyleContent(): string {
    const bySelector: Record<string, string[]> = {}
    for (const [comp, vars] of Object.entries(this.componentVarOverrides)) {
        const entries = Object.entries(vars).filter(([, v]) => v)
        if (!entries.length) continue
        const selector = COMPONENT_SELECTORS[comp] || `.b-${comp}`
        if (!bySelector[selector]) bySelector[selector] = []
        for (const [name, val] of entries) {
            bySelector[selector].push(`  ${name}: ${val};`)
        }
    }
    return Object.entries(bySelector)
        .map(([sel, decls]) => `${sel} {\n${decls.join('\n')}\n}`)
        .join('\n\n')
}

