columnTdAttrs(row: TableRow, column: ITableColumn) {
    if (row.id === "Total") {
        if (column.label === "ID") {
            return {
                colspan: 4,
                class: "has-text-weight-bold",
                style: {
                    "text-align": "left !important",
                },
            };
        } else if (column.label === "Gender") {
            return {
                class: "has-text-weight-semibold",
            };
        } else {
            return {
                style: { display: "none" },
            };
        }
    }
    return null;
}

mounted() {
    const { getTheme, setTheme } = useTheme()
    setTheme(getTheme())

    this.$nextTick(() => {
        const homeHeroElements = document.querySelectorAll('.home-hero');
        const featuresElements = document.querySelectorAll('.features');

        // Add reveal classes with delay
        homeHeroElements.forEach((el, index) => {
            setTimeout(() => {
                el.classList.add('reveal-animation');
            }, index * 100);
        });

        featuresElements.forEach((el, index) => {
            setTimeout(() => {
                el.classList.add('reveal-animation');
            }, 500 + index * 200);
        });
    });
}

function setUserConfig ( config ) {

    var form = document.forms[ 'data-form' ];

    config.title && ( form[ 'title' ].value = config.title );
    config.subTitle && ( form[ 'sub-title' ].value = config.subTitle );
    config.xTitle && ( form[ 'x-title' ].value = config.xTitle );
    config.yTitle && ( form[ 'y-title' ].value = config.yTitle );
    config.suffix && ( form[ 'unit' ].value = config.suffix );
    config.dataFormat == "-1" && ( form[ 'charts-format' ][ 1 ].checked = true );
    config.tip && ( form[ 'tip' ].value = config.tip );
    currentChartType = config.chartType || 0;

}

function switchTab( index ) {

    autoHeight( index );
    if ( emotion.tabExist[index] == 0 ) {
        emotion.tabExist[index] = 1;
        createTab( 'tab' + index );
    }
    //获取呈现元素句柄数组
    var tabHeads = $G( "tabHeads" ).getElementsByTagName( "span" ),
            tabBodys = $G( "tabBodys" ).getElementsByTagName( "div" ),
            i = 0, L = tabHeads.length;
    //隐藏所有呈现元素
    for ( ; i < L; i++ ) {
        tabHeads[i].className = "";
        tabBodys[i].style.display = "none";
    }
    //显示对应呈现元素
    tabHeads[index].className = "focus";
    tabBodys[index].style.display = "block";
}

function () {
    var n = navigator;
    if (n.plugins && n.mimeTypes.length) {
        var plugin = n.plugins["Shockwave Flash"];
        if (plugin && plugin.description) {
            return plugin.description
                    .replace(/([a-zA-Z]|\s)+/, "")
                    .replace(/(\s)+r/, ".") + ".0";
        }
    } else if (window.ActiveXObject && !window.opera) {
        for (var i = 12; i >= 2; i--) {
            try {
                var c = new ActiveXObject('ShockwaveFlash.ShockwaveFlash.' + i);
                if (c) {
                    var version = c.GetVariable("$version");
                    return version.replace(/WIN/g,'').replace(/,/g,'.');
                }
            } catch(e) {}
        }
    }
}
